import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './app.css';
import AICoach from './components/AICoach';
import Therapy from './components/Therapy';
import Community from './components/Community';
import Report from './components/Report';
import Profile from './components/Profile';
import Chat from './components/Chat';


const MoodMate = () => {
  const [activeTab, setActiveTab] = useState('chat');
  const [user, setUser] = useState({
    username: 'Arnav._.singh__',
    id: 1,
    is_premium: true,
    streak: 1, // Will be updated by fetch
    lastMood: 'low',
    lastSession: 'kal raat'
  });
  
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications] = useState([
    { id: 1, text: "5 coins earned for your check-in!", time: "2m ago", unread: true },
    { id: 2, text: "Someone reacted to your Tribe post", time: "1h ago", unread: false },
    { id: 3, text: "Your Weekly Report is ready", time: "3h ago", unread: false }
  ]);

  // Sync Global User State with Backend
  useEffect(() => {
    const fetchUserStatus = async () => {
      try {
        const response = await fetch(`http://localhost:5000/api/user/status?user_id=${user.id}`);
        const data = await response.json();
        if (data.status === 'success') {
          setUser(prev => ({
            ...prev,
            streak: data.streak || 1,
            lastMood: data.last_mood || 'neutral',
            coins: data.coins || 0
          }));
        }
      } catch (err) {
        console.error("Sync failed:", err);
      }
    };
    fetchUserStatus();
  }, []);

  return (
    <div className="app-container">
      <AnimatePresence>
        {/* Header */}
        <header className="app-header">
          <div className="header-left">
            <h1>MoodMate</h1>
            <div className="nav-tabs">
              {[
                { id: 'chat', icon: '💬', label: 'Chat' },
                { id: 'ai-coach', icon: '🤖', label: 'AI Coach' },
                { id: 'therapy', icon: '👨‍⚕️', label: 'Therapy' },
                { id: 'community', icon: '🌍', label: 'Community' },
                { id: 'report', icon: '📊', label: 'Report' },
                { id: 'profile', icon: '👤', label: 'Profile' }
              ].map(tab => (
                <button 
                  key={tab.id}
                  className={activeTab === tab.id ? 'nav-tab active' : 'nav-tab'}
                  onClick={() => setActiveTab(tab.id)}
                >
                  {tab.icon} {tab.label}
                </button>
              ))}
            </div>
          </div>
          <div className="header-right" style={{ display: 'flex', alignItems: 'center', gap: '20px', position: 'relative' }}>
            <div 
              style={{ position: 'relative', cursor: 'pointer', padding: '8px', borderRadius: '50%', background: showNotifications ? '#f1f5f9' : 'transparent' }} 
              onClick={() => setShowNotifications(!showNotifications)}
              title="Notifications"
            >
               <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={showNotifications ? "#4F46E5" : "#64748b"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path>
                  <path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
               </svg>
               <div style={{ position: 'absolute', top: '6px', right: '6px', width: '9px', height: '9px', background: '#ef4444', borderRadius: '50%', border: '2px solid white' }}></div>
               
               {/* Notification Dropdown */}
               <AnimatePresence>
                 {showNotifications && (
                   <motion.div 
                     initial={{ opacity: 0, y: 10, scale: 0.95 }}
                     animate={{ opacity: 1, y: 0, scale: 1 }}
                     exit={{ opacity: 0, y: 10, scale: 0.95 }}
                     style={{ position: 'absolute', top: '50px', right: '0', width: '280px', background: 'white', borderRadius: '16px', boxShadow: '0 15px 40px rgba(0,0,0,0.15)', border: '1px solid #e2e8f0', zIndex: 2000, overflow: 'hidden' }}
                     onClick={e => e.stopPropagation()}
                   >
                      <div style={{ padding: '15px', borderBottom: '1px solid #f1f5f9', fontWeight: 'bold', display: 'flex', justifyContent: 'space-between' }}>
                        <span>Notifications</span>
                        <span style={{ color: '#4F46E5', fontSize: '12px', cursor: 'pointer' }}>Mark all as read</span>
                      </div>
                      <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
                        {notifications.map(n => (
                          <div key={n.id} style={{ padding: '12px 15px', borderBottom: '1px solid #f8fafc', background: n.unread ? 'rgba(79, 70, 229, 0.03)' : 'transparent', transition: 'background 0.2s' }}>
                            <div style={{ fontSize: '13px', color: '#0f172a', marginBottom: '4px' }}>{n.text}</div>
                            <div style={{ fontSize: '11px', color: '#94a3b8' }}>{n.time}</div>
                          </div>
                        ))}
                      </div>
                      <div style={{ padding: '12px', textAlign: 'center', background: '#f8fafc', fontSize: '12px', color: '#64748b', cursor: 'pointer' }}>
                        View all activity
                      </div>
                   </motion.div>
                 )}
               </AnimatePresence>
            </div>
            
            <div 
              onClick={() => setActiveTab('profile')}
              style={{ width: '40px', height: '40px', borderRadius: '50%', background: 'linear-gradient(135deg, #FF007F, #7000FF)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold', fontSize: '16px', cursor: 'pointer', boxShadow: '0 4px 15px rgba(112,0,255,0.3)', transition: 'transform 0.2s' }} 
              onMouseOver={e => e.currentTarget.style.transform='scale(1.05)'} 
              onMouseOut={e => e.currentTarget.style.transform='scale(1)'}
              title="Profile & Settings"
            >
              {user.username.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <main className="app-main">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.98 }}
              transition={{ duration: 0.3, ease: 'easeOut' }}
              style={{ width: '100%', height: '100%' }}
            >
              {activeTab === 'chat' && <Chat user={user} />}
              {activeTab === 'ai-coach' && <AICoach user={user} />}
              {activeTab === 'therapy' && <Therapy user={user} />}
              {activeTab === 'community' && <Community user={user} />}
              {activeTab === 'report' && <Report user={user} />}
              {activeTab === 'profile' && <Profile user={user} />}
            </motion.div>
          </AnimatePresence>
        </main>
      </AnimatePresence>
    </div>
  );
};

export default MoodMate;
